:root {
  --card-bg: #ffffff;
  --card-border: #e2e8f0;
  --card-radius: 16px;

  --header-bg: #0f172a;
  --header-text: #f8fafc;
  --lang-level-color: #94a3b8;

  --streak-bg: #ff6b00;
  --streak-text: #ffffff;
  --streak-radius: 20px;

  --xp-track-bg: #e2e8f0;
  --xp-fill-color: #7c3aed;
  --xp-fill-width: 68%;
  --xp-title-color: #475569;
  --xp-value-color: #7c3aed;

  --skill-bar-bg: #f1f5f9;
  --skill-bar-radius: 4px;
  --skill-pct-color: #64748b;

  --reading-color: #0ea5e9;
  --listening-color: #10b981;
  --speaking-color: #f59e0b;
  --writing-color: #ec4899;

  --reading-width: 78%;
  --listening-width: 61%;
  --speaking-width: 45%;
  --writing-width: 53%;

  --stat-box-bg: #f8fafc;
  --stat-box-border: #e2e8f0;
  --stat-num-color: #0f172a;
  --stat-desc-color: #94a3b8;

  --footer-border: #e2e8f0;
  --next-dot-color: #10b981;
  --next-text-color: #475569;

  --btn-bg: #7c3aed;
  --btn-text: #ffffff;
  --btn-radius: 8px;
}

.card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--card-radius);
  width: 500px;
  overflow: hidden;
  margin: 0 auto;
}

.card-header {
  background: var(--header-bg);
  padding: 14px 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.lang-info {
  display: flex;
  align-items: center;
  gap: 12px;
}

.flag {
  font-size: 28px;
  line-height: 1;
}

.lang-name {
  font-size: 18px;
  font-weight: 700;
  color: var(--header-text);
  line-height: 1.2;
}

.lang-level {
  font-size: 12px;
  color: var(--lang-level-color);
  margin-top: 2px;
}

.streak-badge {
  background: var(--streak-bg);
  border-radius: var(--streak-radius);
  padding: 6px 12px;
  display: flex;
  align-items: center;
  gap: 5px;
}

.streak-icon {
  font-size: 14px;
}

.streak-count {
  font-size: 16px;
  font-weight: 700;
  color: var(--streak-text);
}

.streak-label {
  font-size: 12px;
  color: var(--streak-text);
  opacity: 0.9;
}

.xp-bar-section {
  padding: 12px 18px 10px;
  border-bottom: 1px solid var(--card-border);
}

.xp-labels {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 6px;
}

.xp-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--xp-title-color);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.xp-value {
  font-size: 12px;
  font-weight: 700;
  color: var(--xp-value-color);
}

.xp-track {
  background: var(--xp-track-bg);
  border-radius: 6px;
  height: 10px;
  width: 100%;
}

.xp-fill {
  background: var(--xp-fill-color);
  border-radius: 6px;
  height: 100%;
  width: var(--xp-fill-width);
}

.skills-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  padding: 12px 18px;
  border-bottom: 1px solid var(--card-border);
}

.skill-item {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.skill-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.skill-name {
  font-size: 12px;
  font-weight: 600;
  color: var(--xp-title-color);
}

.skill-pct {
  font-size: 12px;
  font-weight: 700;
  color: var(--skill-pct-color);
}

.skill-bar {
  background: var(--skill-bar-bg);
  border-radius: var(--skill-bar-radius);
  height: 7px;
}

.skill-fill {
  height: 100%;
  border-radius: var(--skill-bar-radius);
}

.skill-fill.reading {
  background: var(--reading-color);
  width: var(--reading-width);
}

.skill-fill.listening {
  background: var(--listening-color);
  width: var(--listening-width);
}

.skill-fill.speaking {
  background: var(--speaking-color);
  width: var(--speaking-width);
}

.skill-fill.writing {
  background: var(--writing-color);
  width: var(--writing-width);
}

.stats-row {
  display: flex;
  gap: 8px;
  padding: 12px 18px;
  border-bottom: 1px solid var(--card-border);
}

.stat-box {
  flex: 1;
  background: var(--stat-box-bg);
  border: 1px solid var(--stat-box-border);
  border-radius: 10px;
  padding: 8px 6px;
  text-align: center;
}

.stat-num {
  font-size: 16px;
  font-weight: 800;
  color: var(--stat-num-color);
  line-height: 1.2;
}

.stat-desc {
  font-size: 10px;
  color: var(--stat-desc-color);
  margin-top: 2px;
  line-height: 1.3;
}

.card-footer {
  padding: 10px 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.next-lesson {
  display: flex;
  align-items: center;
  gap: 8px;
}

.next-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--next-dot-color);
  flex-shrink: 0;
}

.next-text {
  font-size: 12px;
  color: var(--next-text-color);
}

.continue-btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: var(--btn-radius);
  padding: 8px 16px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
  white-space: nowrap;
}
